#include "json_min.h"
static int streq_at(const char *s, const char *k) { while (*k) { if (*s++ != *k++) return 0; } return 1; }
static int is_ws(char c) { return c == ' ' || c == '\t' || c == '\r' || c == '\n'; }
static const char *find_key(const char *json, const char *key) { const char *p; p = json; while (*p) { if (*p == '\"' && streq_at(p + 1, key)) { p++; while (*p && *p != '\"') p++; if (*p == '\"') { p++; while (is_ws(*p)) p++; if (*p == ':') return p + 1; } } p++; } return 0; }
LONG json_find_string(const char *json, const char *key, char *out, UWORD out_size) { const char *p; UWORD n; p = find_key(json, key); if (!p) return -1; while (is_ws(*p)) p++; if (*p != '\"') return -1; p++; n = 0; while (*p && *p != '\"' && n + 1 < out_size) out[n++] = *p++; out[n] = 0; return (*p == '\"') ? 0 : -1; }
LONG json_find_long(const char *json, const char *key, ULONG *out) { const char *p; ULONG v; p = find_key(json, key); if (!p) return -1; while (is_ws(*p)) p++; v = 0; while (*p >= '0' && *p <= '9') { v = v * 10UL + (ULONG)(*p - '0'); p++; } *out = v; return 0; }
WORD json_parse_centideg(const char *s, WORD *out) { LONG sign; LONG whole; LONG frac; LONG nfrac; LONG v; sign = 1; whole = 0; frac = 0; nfrac = 0; if (*s == '-') { sign = -1; s++; } else if (*s == '+') s++; while (*s >= '0' && *s <= '9') { whole = whole * 10 + (*s - '0'); s++; } if (*s == '.') { s++; while (*s >= '0' && *s <= '9' && nfrac < 2) { frac = frac * 10 + (*s - '0'); nfrac++; s++; } } while (nfrac < 2) { frac *= 10; nfrac++; } v = sign * (whole * 100 + frac); if (v < -32768L || v > 32767L) return -1; *out = (WORD)v; return 0; }
